def most_repeated_letters(input_str):
    """
    Analyzes a string to find:
    1. The most repeated letter(s)
    2. Count of each letter

    Args:
        input_str (str): A string of lowercase letters with spaces

    Returns:
        dict: {
            'most_repeated': list of most frequent letter(s),
            'letter_counts': dict of all letters and their counts
        }
        Example: {
            'most_repeated': ['l', 'o'],
            'letter_counts': {'h':1, 'e':1, 'l':3, 'o':2, 'w':1, 'r':1, 'd':1}
        }
    """
    # Process input
    filtered_str = input_str.replace(" ", "")

    # Initialize results
    result = {
        'most_repeated': [],
        'letter_counts': {}
    }

    if not filtered_str:
        return result

    # Count letters and track max
    max_count = 0
    for char in filtered_str:
        result['letter_counts'][char] = result['letter_counts'].get(char, 0) + 1
        current_count = result['letter_counts'][char]

        # Update max tracking
        if current_count > max_count:
            max_count = current_count
            result['most_repeated'] = [char]
        elif current_count == max_count:
            if char not in result['most_repeated']:
                result['most_repeated'].append(char)

    return result

