def is_valid_date(date_str, format_str="YYYY-MM-DD"):
    """
    Check if a date string is valid based on the specified format.

    Args:
        date_str (str): The date string to validate (e.g., "2023-12-31").
        format_str (str): The expected format (e.g., "YYYY-MM-DD", "DD/MM/YYYY").
                      Defaults to "YYYY-MM-DD".

    Returns:
        bool: True if the date is valid, False otherwise.
    """
    try:
        if format_str == "YYYY-MM-DD":
            year, month, day = map(int, date_str.split('-'))
        elif format_str == "DD/MM/YYYY":
            day, month, year = map(int, date_str.split('/'))
        else:
            raise ValueError("Unsupported date format")

        # Validate month
        if month < 1 or month > 12:
            return False

        # Validate day
        if day < 1 or day > 31:
            return False

        # Check month-specific day limits
        if month in [4, 6, 9, 11] and day > 30:
            return False
        elif month == 2:
            # Leap year check for February
            if (year % 400 == 0) or (year % 100 != 0 and year % 4 == 0):
                if day > 29:
                    return False
            else:
                if day > 28:
                    return False

        return True

    except (ValueError, IndexError):
        return False

