def is_power(x, n):
    """
    Check if x is a power of n (i.e., x = n^k for some integer k).
    Returns False for cases like 3 being a power of 2.
    """
    if n == 1:
        return x == 1
    if x == 1:
        return True
    if x == n:
        return True
    if x <= 0 or n <= 0:
        return False

    power = 1
    while power < x:
        power *= n
        if power == x:
            return True
    return False
